import { defineConfig } from "vite";
import { redwood } from "rwsdk/vite";
import { cloudflare } from "@cloudflare/vite-plugin";

export default defineConfig({
  plugins: [
    cloudflare({
      viteEnvironment: { name: "worker" },
    }),
    redwood(),
  ],
});

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  render(Document, [route("/", Home)]),
]);

import { initClient, initClientNavigation } from "rwsdk/client";

// RedwoodSDK uses RSC RPC to emulate client side navigation.
// https://docs.rwsdk.com/guides/frontend/client-side-nav/
const { handleResponse, onHydrated } = initClientNavigation();
initClient({ handleResponse, onHydrated });

import { RouteMiddleware } from "rwsdk/router";

export const setCommonHeaders =
  (): RouteMiddleware =>
  ({ response, rw: { nonce } }) => {
    if (!import.meta.env.VITE_IS_DEV_SERVER) {
      // Forces browsers to always use HTTPS for a specified time period (2 years)
      response.headers.set(
        "Strict-Transport-Security",
        "max-age=63072000; includeSubDomains; preload",
      );
    }

    // Forces browser to use the declared content-type instead of trying to guess/sniff it
    response.headers.set("X-Content-Type-Options", "nosniff");

    // Stops browsers from sending the referring webpage URL in HTTP headers
    response.headers.set("Referrer-Policy", "no-referrer");

    // Explicitly disables access to specific browser features/APIs
    response.headers.set(
      "Permissions-Policy",
      "geolocation=(), microphone=(), camera=()",
    );

    // Defines trusted sources for content loading and script execution:
    response.headers.set(
      "Content-Security-Policy",
      `default-src 'self'; script-src 'self' 'unsafe-eval' 'nonce-${nonce}' https://challenges.cloudflare.com; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; font-src 'self' https://fonts.gstatic.com; frame-ancestors 'self'; frame-src 'self' https://challenges.cloudflare.com; object-src 'none';`,
    );
  };

import { Welcome } from "./welcome.js";

export const Home = () => {
  // _Feel free to delete this element and its import_
  return <Welcome />;
};

import { linkFor } from "rwsdk/router";
import type { App } from "rwsdk/worker";

export const link = linkFor<App>();

"use client";
/**
 * This is a minimal welcome page for the starter.
 *
 * _Feel free to delete this file_
 **/

import { useState } from "react";
import styles from "./welcome.module.css";

export const Welcome = () => {
  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1 className={styles.title}>Welcome to RedwoodSDK</h1>
        <p className={styles.subtitle}>
          You’ve just installed the starter project. Here’s what to do next.
        </p>
      </header>

      <main>
        <section className={styles.section}>
          <h2 className={styles.sectionTitle}>Next steps</h2>
          <ol className={styles.list}>
            <li>
              Read the{" "}
              <a
                href="https://docs.rwsdk.com/getting-started/quick-start/"
                target="_blank"
                rel="noreferrer"
                className={styles.link}
              >
                Quick Start
              </a>{" "}
              to learn the basics.
            </li>
            <li>
              Explore React Server Components and Server Functions in the{" "}
              <a
                href="https://docs.rwsdk.com/"
                target="_blank"
                rel="noreferrer"
                className={styles.link}
              >
                Docs
              </a>
              .
            </li>
            <li>
              Join the community to ask questions and share what you’re
              building.
            </li>
          </ol>
        </section>

        <section className={styles.section}>
          <h2 className={styles.sectionTitle}>Deploy to Cloudflare</h2>
          <p>
            RedwoodSDK runs on Cloudflare Workers. Here’s the quickest way to
            deploy.
          </p>
          <div className={styles.codeBlock}>
            <span className={styles.codePrompt}>$</span>
            <code className={styles.code}>pnpm release</code>
            <Copy textToCopy="pnpm release" />
          </div>
          <p>
            Need more detail? Read the{" "}
            <a
              href="https://docs.rwsdk.com/core/hosting/"
              target="_blank"
              rel="noreferrer"
              className={styles.link}
            >
              Cloudflare deployment guide
            </a>
            .
          </p>
        </section>
      </main>
    </div>
  );
};

const Copy = ({ textToCopy }: { textToCopy: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(textToCopy).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <button onClick={handleCopy} className={styles.copyButton}>
      {copied ? "Copied!" : "Copy"}
    </button>
  );
};

import React from "react";
import { RequestInfo } from "../requestInfo/types";
import type { DocumentProps, LayoutProps } from "./types.js";
type MaybePromise<T> = T | Promise<T>;
type BivariantRouteHandler<T extends RequestInfo, R> = {
    bivarianceHack(requestInfo: T): R;
}["bivarianceHack"];
export type RouteMiddleware<T extends RequestInfo = RequestInfo> = BivariantRouteHandler<T, MaybePromise<React.JSX.Element | Response | void>>;
export type ExceptHandler<T extends RequestInfo = RequestInfo> = {
    __rwExcept: true;
    handler: (error: unknown, requestInfo: T) => MaybePromise<React.JSX.Element | Response | void>;
    pathPattern?: string;
};
type RouteFunction<T extends RequestInfo = RequestInfo> = BivariantRouteHandler<T, MaybePromise<Response>>;
type RouteComponent<T extends RequestInfo = RequestInfo> = BivariantRouteHandler<T, MaybePromise<React.JSX.Element | Response | void>>;
type RouteHandler<T extends RequestInfo = RequestInfo> = RouteFunction<T> | RouteComponent<T> | readonly [...RouteMiddleware<T>[], RouteFunction<T> | RouteComponent<T>];
declare const METHOD_VERBS: readonly ["delete", "get", "head", "patch", "post", "put"];
export type MethodVerb = (typeof METHOD_VERBS)[number];
export type MethodHandlers<T extends RequestInfo = RequestInfo> = {
    [K in MethodVerb]?: RouteHandler<T>;
} & {
    config?: {
        disable405?: true;
        disableOptions?: true;
    };
    custom?: {
        [method: string]: RouteHandler<T>;
    };
};
export type Route<T extends RequestInfo = RequestInfo> = RouteMiddleware<T> | RouteDefinition<string, T> | ExceptHandler<T> | readonly Route<T>[];
type NormalizedRouteDefinition<T extends RequestInfo = RequestInfo> = {
    path: string;
    handler: RouteHandler<T> | MethodHandlers<T>;
    layouts?: React.FC<LayoutProps<T>>[];
};
export type RouteDefinition<Path extends string = string, T extends RequestInfo = RequestInfo> = NormalizedRouteDefinition<T> & {
    readonly __rwPath?: Path;
};
type TrimTrailingSlash<S extends string> = S extends `${infer Head}/` ? TrimTrailingSlash<Head> : S;
type TrimLeadingSlash<S extends string> = S extends `/${infer Rest}` ? TrimLeadingSlash<Rest> : S;
type NormalizePrefix<Prefix extends string> = TrimTrailingSlash<TrimLeadingSlash<Prefix>> extends "" ? "" : `/${TrimTrailingSlash<TrimLeadingSlash<Prefix>>}`;
type NormalizePath<Path extends string> = TrimTrailingSlash<Path> extends "/" ? "/" : `/${TrimTrailingSlash<TrimLeadingSlash<Path>>}`;
type JoinPaths<Prefix extends string, Path extends string> = NormalizePrefix<Prefix> extends "" ? NormalizePath<Path> : Path extends "/" ? NormalizePrefix<Prefix> : `${NormalizePrefix<Prefix>}${NormalizePath<Path>}`;
type PrefixedRouteValue<Prefix extends string, Value> = Value extends RouteDefinition<infer Path, infer Req> ? RouteDefinition<JoinPaths<Prefix, Path>, Req> : Value extends ExceptHandler<any> ? Value : Value extends readonly Route<any>[] ? PrefixedRouteArray<Prefix, Value> : Value;
type PrefixedRouteArray<Prefix extends string, Routes extends readonly Route<any>[]> = Routes extends readonly [] ? [] : Routes extends readonly [infer Head, ...infer Tail] ? readonly [
    PrefixedRouteValue<Prefix, Head>,
    ...PrefixedRouteArray<Prefix, Tail extends readonly Route<any>[] ? Tail : []>
] : ReadonlyArray<PrefixedRouteValue<Prefix, Routes[number]>>;
export declare function matchPath<T extends RequestInfo = RequestInfo>(routePath: string, requestPath: string): T["params"] | null;
export declare function defineRoutes<T extends RequestInfo = RequestInfo>(routes: readonly Route<T>[]): {
    routes: Route<T>[];
    handle: ({ request, renderPage, getRequestInfo, onError, runWithRequestInfoOverrides, rscActionHandler, }: {
        request: Request;
        renderPage: (requestInfo: T, Page: React.FC, onError: (error: unknown) => void) => Promise<Response>;
        getRequestInfo: () => T;
        onError: (error: unknown) => void;
        runWithRequestInfoOverrides: <Result>(overrides: Partial<T>, fn: () => Promise<Result>) => Promise<Result>;
        rscActionHandler: (request: Request) => Promise<unknown>;
    }) => Response | Promise<Response>;
};
/**
 * Defines a route handler for a path pattern.
 *
 * Supports three types of path patterns:
 * - Static: /about, /contact
 * - Parameters: /users/:id, /posts/:postId/edit
 * - Wildcards: /files/\*, /api/\*\/download
 *
 * @example
 * // Static route
 * route("/about", () => <AboutPage />)
 *
 * @example
 * // Route with parameters
 * route("/users/:id", ({ params }) => {
 *   return <UserProfile userId={params.id} />
 * })
 *
 * @example
 * // Route with wildcards
 * route("/files/*", ({ params }) => {
 *   const filePath = params.$0
 *   return <FileViewer path={filePath} />
 * })
 *
 * @example
 * // Method-based routing
 * route("/api/users", {
 *   get: () => Response.json(users),
 *   post: ({ request }) => Response.json({ status: "created" }, { status: 201 }),
 *   delete: () => new Response(null, { status: 204 }),
 * })
 *
 * @example
 * // Route with middleware array
 * route("/admin", [isAuthenticated, isAdmin, () => <AdminDashboard />])
 */
export declare function route<Path extends string, T extends RequestInfo = RequestInfo>(path: Path, handler: RouteHandler<T> | MethodHandlers<T>): RouteDefinition<NormalizePath<Path>, T>;
/**
 * Defines a route handler for the root path "/".
 *
 * @example
 * // Homepage
 * index(() => <HomePage />)
 *
 * @example
 * // With middleware
 * index([logRequest, () => <HomePage />])
 */
export declare function index<T extends RequestInfo = RequestInfo>(handler: RouteHandler<T>): RouteDefinition<"/", T>;
/**
 * Defines an error handler that catches errors from routes, middleware, and RSC actions.
 *
 * @example
 * // Global error handler
 * except((error, requestInfo) => {
 *   console.error(error);
 *   return new Response("Internal Server Error", { status: 500 });
 * })
 *
 * @example
 * // Error handler that returns a React component
 * except((error) => {
 *   return <ErrorPage error={error} />;
 * })
 */
export declare function except<T extends RequestInfo = RequestInfo>(handler: (error: unknown, requestInfo: T) => MaybePromise<React.JSX.Element | Response | void>): ExceptHandler<T>;
export declare function prefix<Prefix extends string, T extends RequestInfo = RequestInfo, Routes extends readonly Route<T>[] = readonly Route<T>[]>(prefixPath: Prefix, routes: Routes): PrefixedRouteArray<Prefix, Routes>;
export declare const wrapHandlerToThrowResponses: <T extends RequestInfo = RequestInfo>(handler: RouteFunction<T> | RouteComponent<T>) => RouteHandler<T>;
/**
 * Wraps routes with a layout component.
 *
 * @example
 * // Define a layout component
 * function BlogLayout({ children }: { children?: React.ReactNode }) {
 *   return (
 *     <div>
 *       <nav>Blog Navigation</nav>
 *       <main>{children}</main>
 *     </div>
 *   )
 * }
 *
 * // Apply layout to routes
 * const blogRoutes = layout(BlogLayout, [
 *   route("/", () => <BlogIndex />),
 *   route("/post/:id", ({ params }) => <BlogPost id={params.id} />),
 * ])
 */
export declare function layout<TLayout extends RequestInfo = RequestInfo, Routes extends readonly Route<any>[] = readonly Route<any>[]>(LayoutComponent: React.FC<LayoutProps<TLayout>>, routes: Routes): Routes;
/**
 * Wraps routes with a Document component and configures rendering options.
 *
 * @param options.rscPayload - Toggle the RSC payload that's appended to the Document. Disabling this will mean that interactivity no longer works.
 * @param options.ssr - Disable sever side rendering for all these routes. This only allow client side rendering, which requires `rscPayload` to be enabled.
 *
 * @example
 * // Basic usage
 * defineApp([
 *   render(Document, [
 *     route("/", () => <HomePage />),
 *     route("/about", () => <AboutPage />),
 *   ]),
 * ])
 *
 * @example
 * // With custom rendering options
 * render(Document, [
 *   route("/", () => <HomePage />),
 * ], {
 *   rscPayload: true,
 *   ssr: true,
 * })
 */
type RenderedRoutes<T extends RequestInfo, Routes extends readonly Route<T>[]> = readonly [RouteMiddleware<T>, ...Routes];
export declare function render<T extends RequestInfo = RequestInfo, Routes extends readonly Route<T>[] = readonly Route<T>[]>(Document: React.FC<DocumentProps<T>>, routes: Routes, options?: {
    rscPayload?: boolean;
    ssr?: boolean;
}): RenderedRoutes<T, Routes>;
export declare const isClientReference: (value: any) => boolean;
export {};

import React from "react";
import { DefaultAppContext, RequestInfo } from "./requestInfo/types";
import { Route } from "./lib/router";
export * from "./requestInfo/types";
declare global {
    type Env = {
        ASSETS: Fetcher;
        DB: D1Database;
    };
}
export type AppDefinition<Routes extends readonly Route<any>[], T extends RequestInfo> = {
    fetch: (request: Request, env: Env, cf: ExecutionContext) => Promise<Response>;
    __rwRoutes: Routes;
};
export interface DefineAppOptions {
    allowedOrigins?: readonly string[];
}
export declare const defineApp: <T extends RequestInfo = RequestInfo<any, DefaultAppContext>, Routes extends readonly Route<T>[] = readonly Route<T>[]>(routes: Routes, options?: DefineAppOptions) => AppDefinition<Routes, T>;
export declare const DefaultDocument: React.FC<{
    children: React.ReactNode;
}>;

type Interruptor<TArgs extends any[] = any[]> = (context: {
    request: Request;
    ctx: Record<string, any>;
    args: TArgs;
}) => Promise<Response | void> | Response | void;
type ServerFunction<TArgs extends any[] = any[], TResult = any> = (...args: TArgs) => Promise<TResult>;
type ServerFunctionOptions = {
    method?: "GET" | "POST";
};
type WrappedServerFunction<TArgs extends any[] = any[], TResult = any> = {
    (...args: TArgs): Promise<TResult>;
    method?: "GET" | "POST";
};
export type ServerFunctionWrap = (fn: Function, args: any[], type: "action" | "query") => Promise<any>;
/**
 * Register a wrapper that runs around every server action and query handler.
 *
 * Call this once in your worker entry point. The wrapper receives the main
 * handler function, its arguments, and the type ("action" or "query").
 * Interruptors run *outside* the wrapper.
 *
 * Only one wrapper is active at a time; the most recent call wins.
 *
 * @example
 * ```ts
 * import { registerServerFunctionWrap } from "rwsdk/worker";
 * import * as Sentry from "@sentry/cloudflare";
 *
 * registerServerFunctionWrap((fn, args, type) =>
 *   Sentry.startSpan(
 *     { name: fn.name, op: `function.rsc_${type}` },
 *     () => fn(...args)
 *   )
 * );
 * ```
 */
export declare function registerServerFunctionWrap(wrap: ServerFunctionWrap): void;
/**
 * @internal Reset the global wrap — only for tests.
 */
export declare function __resetServerFunctionWrap(): void;
/**
 * Wrap a function to be used as a server query.
 *
 * - **Method**: Defaults to `GET`. can be changed via `options`.
 * - **Behavior**: When called from the client, it returns data-only and does **not** rehydrate or re-render the React page.
 * - **Location**: Must be defined in a file with `"use server"`. We recommend `queries.ts` colocated with components.
 * - **Middleware**: You can pass an array of functions as the first argument to act as interruptors (e.g. for auth).
 *
 * @example
 * ```ts
 * // getters.ts
 * "use server"
 *
 * export const getUser = serverQuery(async (id: string) => {
 *   return db.user.findUnique({ where: { id } })
 * })
 * ```
 */
export declare function serverQuery<TArgs extends any[], TResult>(fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>], options?: ServerFunctionOptions): WrappedServerFunction<TArgs, TResult>;
/**
 * Wrap a function to be used as a server action.
 *
 * - **Method**: Defaults to `POST`. can be changed via `options`.
 * - **Behavior**: When called from the client, it **will** rehydrate and re-render the React page with the new server state.
 * - **Location**: Must be defined in a file with `"use server"`. We recommend `actions.ts` colocated with components.
 * - **Middleware**: You can pass an array of functions as the first argument to act as interruptors (e.g. for auth).
 *
 * @example
 * ```ts
 * // actions.ts
 * "use server"
 *
 * export const updateUser = serverAction(async (id: string, data: any) => {
 *   return db.user.update({ where: { id }, data })
 * })
 * ```
 */
export declare function serverAction<TArgs extends any[], TResult>(fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>], options?: ServerFunctionOptions): WrappedServerFunction<TArgs, TResult>;
export {};

import "./types/shared";
export * from "../lib/links";
export * from "../lib/router";

import "server-only";
import "./types/worker";
export * from "../error";
export * from "../lib/types";
export * from "../lib/utils";
export * from "../register/worker";
export * from "../render/renderToStream";
export * from "../render/renderToString";
export * from "../requestInfo/types";
export * from "../requestInfo/utils";
export * from "../requestInfo/worker";
export * from "../script";
export * from "../server";
export * from "../worker";

import { jsx as _jsx, jsxs as _jsxs } from "react/jsx-runtime";
import { normalizeActionResult } from "./render/normalizeActionResult";
import { renderDocumentHtmlStream } from "./render/renderDocumentHtmlStream";
import { renderToRscStream } from "./render/renderToRscStream";
import { injectRSCPayload } from "rsc-html-stream/server";
import { ErrorResponse } from "./error";
import { createRscActionHandler } from "./register/worker";
import { getRequestInfo, runWithRequestInfo, runWithRequestInfoOverrides, } from "./requestInfo/worker";
import { ssrWebpackRequire } from "./imports/worker";
import { defineRoutes } from "./lib/router";
import { generateNonce } from "./lib/utils";
export * from "./requestInfo/types";
export const defineApp = (routes, options = {}) => {
    const router = defineRoutes(routes);
    const rscActionHandler = createRscActionHandler({
        allowedOrigins: options.allowedOrigins,
    });
    return {
        __rwRoutes: routes,
        fetch: async (request, env, cf) => {
            globalThis.__webpack_require__ = ssrWebpackRequire;
            // context(justinvdm, 17 Mar 2026): Strip the Vite base path from the
            // request URL so that routes defined as "/" match requests to "/app/"
            // when base: '/app/' is configured. Vite injects BASE_URL automatically.
            const base = import.meta.env.BASE_URL;
            if (base && base !== "/") {
                const url = new URL(request.url);
                if (url.pathname.startsWith(base)) {
                    url.pathname = "/" + url.pathname.slice(base.length);
                    request = new Request(url.toString(), request);
                }
            }
            // context(justinvdm, 5 Feb 2025): Serve assets requests using the assets service binding
            // todo(justinvdm, 5 Feb 2025): Find a way to avoid this so asset requests are served directly
            // rather than first needing to go through the worker
            if (request.url.includes("/assets/")) {
                const url = new URL(request.url);
                url.pathname = url.pathname.slice("/assets/".length);
                return env.ASSETS.fetch(new Request(url.toString(), request));
            }
            else if (import.meta.env.VITE_IS_DEV_SERVER &&
                new URL(request.url).pathname === "/__worker-run") {
                const expectedToken = import.meta.env
                    .VITE_RWSDK_WORKER_RUN_TOKEN;
                const requestToken = request.headers.get("x-rwsdk-worker-run-token");
                if (!expectedToken || expectedToken !== requestToken) {
                    return new Response("Forbidden", { status: 403 });
                }
                const url = new URL(request.url);
                const scriptPath = url.searchParams.get("script");
                if (!scriptPath) {
                    return new Response("Missing 'script' query parameter", {
                        status: 400,
                    });
                }
                try {
                    const scriptModule = await import(/* @vite-ignore */ scriptPath);
                    if (scriptModule.default) {
                        await scriptModule.default(request, env, cf);
                    }
                    return new Response("Script executed successfully");
                }
                catch (e) {
                    console.error(`Error executing script: ${scriptPath}\n\n${e.stack}`);
                    return new Response(`Error executing script: ${e.message}`, {
                        status: 500,
                    });
                }
            }
            else if (import.meta.env.VITE_IS_DEV_SERVER &&
                request.url.includes("/__vite_preamble__")) {
                return new Response('import RefreshRuntime from "/@react-refresh"; RefreshRuntime.injectIntoGlobalHook(window); window.$RefreshReg$ = () => {}; window.$RefreshSig$ = () => (type) => type; window.__vite_plugin_react_preamble_installed__ = true;', {
                    headers: {
                        "content-type": "text/javascript",
                    },
                });
            }
            try {
                const url = new URL(request.url);
                let path = url.pathname;
                if (path !== "/" && !path.endsWith("/")) {
                    path = path + "/";
                }
                const isRSCRequest = url.searchParams.has("__rsc") ||
                    request.headers.get("accept")?.includes("text/x-component");
                const isAction = url.searchParams.has("__rsc_action_id");
                const rw = {
                    Document: DefaultDocument,
                    nonce: generateNonce(),
                    rscPayload: true,
                    ssr: true,
                    databases: new Map(),
                    scriptsToBeLoaded: new Set(),
                    entryScripts: new Set(),
                    inlineScripts: new Set(),
                    pageRouteResolved: undefined,
                };
                const userResponseInit = {
                    status: 200,
                    headers: new Headers(),
                };
                const outerRequestInfo = {
                    request,
                    path,
                    cf,
                    params: {},
                    ctx: {},
                    rw,
                    response: userResponseInit,
                    isAction,
                };
                const createPageElement = (requestInfo, Page) => {
                    let pageElement;
                    if (isClientReference(Page)) {
                        const { ctx, params } = requestInfo; // context(justinvdm, 25 Feb 2025): If the page is a client reference, we need to avoid passing
                        // down props the client shouldn't get (e.g. env). For safety, we pick the allowed props explicitly.
                        pageElement = _jsx(Page, { ctx: ctx, params: params });
                    }
                    else {
                        pageElement = _jsx(Page, { ...requestInfo });
                    }
                    return pageElement;
                };
                const renderPage = async (requestInfo, Page, _onError) => {
                    if (isClientReference(requestInfo.rw.Document)) {
                        if (import.meta.env.DEV) {
                            console.error("Document cannot be a client component");
                        }
                        return new Response(null, {
                            status: 500,
                        });
                    }
                    // context(justinvdm, 2026-03-17): Capture rendering errors so the
                    // router can throw them and route to except handlers. We store the
                    // error on rw.renderError instead of throwing from renderPage, because
                    // throwing mid-render corrupts React's internal RSC stream state
                    // (causing "chunk.reason.enqueueModel is not a function" in subsequent
                    // renders). By returning normally, streams are cleaned up properly.
                    const onError = (error) => {
                        if (!rw.renderError) {
                            rw.renderError = error;
                        }
                    };
                    const actionResult = normalizeActionResult(requestInfo.rw.actionResult);
                    const isDataOnly = request.headers.get("x-rsc-data-only") === "true";
                    const pageElement = isDataOnly && actionResult !== undefined
                        ? null
                        : createPageElement(requestInfo, Page);
                    if (pageElement === null) {
                        rw.pageRouteResolved?.resolve();
                    }
                    const { rscPayload: shouldInjectRSCPayload } = rw;
                    let rscPayloadStream = renderToRscStream({
                        input: {
                            node: pageElement,
                            actionResult,
                        },
                        onError,
                    });
                    if (isRSCRequest) {
                        const responseHeaders = new Headers(userResponseInit.headers);
                        responseHeaders.set("content-type", "text/x-component; charset=utf-8");
                        return new Response(rscPayloadStream, {
                            status: userResponseInit.status,
                            statusText: userResponseInit.statusText,
                            headers: responseHeaders,
                        });
                    }
                    let injectRSCPayloadStream;
                    if (shouldInjectRSCPayload) {
                        const [rscPayloadStream1, rscPayloadStream2] = rscPayloadStream.tee();
                        rscPayloadStream = rscPayloadStream1;
                        injectRSCPayloadStream = injectRSCPayload(rscPayloadStream2, {
                            nonce: rw.nonce,
                        });
                    }
                    let html;
                    try {
                        html = await renderDocumentHtmlStream({
                            rscPayloadStream: rscPayloadStream,
                            Document: rw.Document,
                            requestInfo: requestInfo,
                            onError,
                            shouldSSR: rw.ssr,
                        });
                    }
                    catch (renderError) {
